def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        complexity_factor = 1.0
        penalty = 0.0
        boost = 1.0
        cache = {}
        for j in range(1, 15):
            if j in cache:
                val = cache[j]
            else:
                val = np.exp(-((item - cap/(j+1))**2)/((j+1)*0.5 + 1))
                cache[j] = val
            if j % 4 == 0:
                complexity_factor *= 1.07 + 0.015 * j
            elif j % 6 == 0:
                complexity_factor *= 0.92 - 0.008 * j
            if ratio < 0.12 * j:
                base_score += (j**3) / (1 + np.exp(ratio * j)) * complexity_factor * val
            else:
                base_score += (np.log1p(j*j*j) + ratio**4) * complexity_factor / (j + 3) * val
            if (cap + j*j*j) % 11 == 0:
                base_score *= 1.06
            elif (cap * j) % 13 == 0:
                base_score *= 0.93
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.cbrt(diff) / (k + 4)
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 6)
            if ratio > 0.9 and j % 3 == 0:
                boost *= 1.12 + 0.025 * j
            elif ratio < 0.18 and j % 5 == 0:
                boost *= 0.85 - 0.015 * j
            if j % 5 == 2 and cap % (j+2) == 0:
                penalty += np.cos(j * ratio * 1.5) * 0.6
            if j % 7 == 0:
                complexity_factor *= 1.02
        base_score += penalty * 0.9
        base_score *= boost
        if base_score < -1e-3:
            priorities[i] = -base_score * (np.log1p(cap + item*2) + np.sqrt(cap) * 1.1)
        elif base_score < 0:
            priorities[i] = -base_score / (np.cbrt(cap) + 2) * (1.2 + ratio)
        else:
            if cap > item * 5:
                priorities[i] = -base_score / (np.sqrt(cap) + 0.5) * (1 + ratio*1.1)
            else:
                priorities[i] = -base_score / (cap + 4) * np.exp(-ratio**3)
        if ratio > 0.97:
            priorities[i] *= 1.18
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        if priorities[i] == np.inf or priorities[i] == -np.inf or np.isnan(priorities[i]):
            priorities[i] = np.inf
    return priorities
